// lock_free.cpp
#include <iostream>
#include <atomic>
int main() {
    // 检查 int 类型的原子操作是否为无锁的
    std::atomic<int> myAtomicInt;
    bool lockFreeInt = myAtomicInt.is_lock_free();
    // 输出结果
    std::cout << "Atomic int is lock-free: " << (lockFreeInt ? "true" : "false") << std::endl;
    // 检查指针类型的原子操作是否为无锁的
    std::atomic<int*> myAtomicPtr;
    bool lockFreePtr = myAtomicPtr.is_lock_free();
    // 输出结果
    std::cout << "Atomic pointer is lock-free: " << (lockFreePtr ? "true" : "false") << std::endl;
    return 0;
}

